def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45 + np.log1p(cap**1.1) * 30 - np.sqrt(abs(cap - usage)) * 12
        fluctuation = 0.0
        complexity_factor = 1.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.2)
            if cap > 15:
                base_priority += (np.cbrt(cap) * 80) + (45 * np.cos(cap * 1.8))
            else:
                base_priority -= 55 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 22 / i
            complexity_factor *= 1.3
        elif 4 < usage <= 5:
            diff = usage - 4
            base_priority += 2500 * diff ** 2 + 300 * np.sqrt(1 - diff)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
                if j % 2 == 0:
                    fluctuation -= 8 / j
            if int(cap * 4) % 5 == 1:
                base_priority += 50 * np.tan(cap / 12)
            complexity_factor *= 1.15
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3)**3
            for k in range(1, 14):
                val = usage ** k
                if val < 0.35:
                    fluctuation += val * 15 / k
                    if k % 4 == 1:
                        fluctuation += 3 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 35
            if cap % 3.1 < 0.7:
                base_priority += 40 * np.sin(cap * 2.7)
            complexity_factor *= 1.1
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 2.5
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 18 / m
                    if m % 6 == 0:
                        fluctuation += 5 * m
                else:
                    fluctuation += (1 - pwr) * 20 / (m + 3)
                    if m in {7, 13} and usage > 2.7:
                        fluctuation += 25
            if cap % 2.7 < 0.6:
                base_priority += 45 * np.cos(cap * 3.2)
            complexity_factor *= 1.05
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 3.5
            for n in range(1, 18):
                val = usage ** n
                if val < 0.65:
                    fluctuation += val * 28 / n
                    if n % 4 == 3:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - val) * 15 / (n + 2)
                    if n == 14 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.8 < 0.4:
                base_priority += 33 * np.sin(cap * 1.9)
        elif 0.6 < usage <= 1:
            base_priority += 160 * (1 - usage) ** 1.5 + 12 * usage
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.08 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 290
            elif cap < 0.95:
                base_priority += np.log1p(cap * 22) * 38
            else:
                base_priority += (cap % 6) * 24
        else:
            base_priority += 300 * (1 - usage) ** 2.2
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 16 / p
                if usage < 0.02 * p:
                    fluctuation -= 13 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 330
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 48
            else:
                base_priority += (cap % 7) * 33
        priority = base_priority + fluctuation * complexity_factor
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.15:
                priority -= 60
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 45
            if usage > 0.9:
                priority += 65
            elif usage < 0.25:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) == 1:
                    priority += r * 9
                else:
                    priority -= r * 4
        else:
            if usage < 0.15:
                priority -= 45
                for s in range(1, 9):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 95
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 2800) % 21 == 0:
            proximity += 18
        if int(cap * 950) % 25 == 0:
            proximity -= 13
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for u in range(1, 11):
            dist = abs(usage - u / 11)
            if dist < 0.025:
                proximity += 22 / u
            elif dist < 0.06:
                proximity += 13 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_check = int(cap * 1700) % (v + 10)
            if mod_check == 0:
                proximity += v * 6
            elif mod_check == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_check = int(usage * 1700) % (w + 7)
            if mod_check == 0:
                proximity += 12 * w
            elif mod_check == 4:
                proximity -= 8 * w
        priority += proximity
        if usage < 0.003:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
        if cap > 2.5:
            if cap % 1 < 0.08:
                priority += 50
            if (int(cap * 2700) % 25 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 650) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
